function solve(nums) {
    const n = nums.length;
    if (n === 1) {
        return 0;
    }

    const sorted = [...nums].sort((a, b) => a - b);
    if (JSON.stringify(nums) === JSON.stringify(sorted)) {
        return 0;
    }

    let maxK = 0;
    for (let i = 0; i < n; i++) {
        if (nums[i] !== sorted[i]) {
            const candidate = nums[i] & sorted[i];
            if (candidate > maxK) {
                maxK = candidate;
            }
        }
    }

    return maxK;
}
